import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('brain-pop'); 

  useEffect(() => {
    // Stage 1: Neural Trace (2s) -> Stage 2: CC Draw (1.5s) -> Stage 3: Main Site
    const timer1 = setTimeout(() => setStage('cc-draw'), 2500);
    const timer2 = setTimeout(() => setStage('main'), 4000);
    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  const featuresRow1 = [
    { title: 'Course Curator', desc: 'AI picks the single best video for your concept.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
    { title: 'Notes Generator', desc: 'Live summaries and key concepts.' },
    { title: 'Course Curator', desc: 'AI picks the single best video.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions.' },
  ];

  const featuresRow2 = [
    { title: 'Revision Scheduler', desc: 'Smart reminders for better retention.' },
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
    { title: 'Premium Features', desc: 'Unlock full learning power.' },
    { title: 'Revision Scheduler', desc: 'Smart reminders.' },
    { title: 'Update Acknowledger', desc: 'Stay updated.' },
  ];

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden font-serif">

      {/* 1. INTRO ANIMATIONS */}
      <AnimatePresence mode="wait">
        {stage === 'brain-pop' && (
          <motion.div
            key="brain-stage"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0, scale: 1.1 }}
            transition={{ duration: 0.5 }}
          >
            {/* NEURAL BRAIN SVG ANIMATION */}
            <svg width="200" height="200" viewBox="0 0 100 100" className="overflow-visible">
              {/* Outer Brain Symmetry - Tracing Paths */}
              <motion.path
                d="M50,15 C30,15 15,35 15,55 C15,75 35,85 50,85 C65,85 85,75 85,55 C85,35 70,15 50,15"
                fill="none"
                stroke="#0B3954"
                strokeWidth="2"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1.5, ease: "easeInOut" }}
              />

              {/* Internal Neural Connections (Lines) */}
              <motion.path
                d="M30,40 L50,50 M70,40 L50,50 M50,50 L50,80 M35,70 L50,50 M65,70 L50,50"
                stroke="#0B3954"
                strokeWidth="1.5"
                strokeOpacity="0.4"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1.2, delay: 0.5 }}
              />

              {/* Central Play Button - Highlighting */}
              <motion.path
                d="M45,42 L60,50 L45,58 Z"
                fill="#0B3954"
                initial={{ opacity: 0, scale: 0.5 }}
                animate={{ opacity: 1, scale: 1.1 }}
                transition={{ 
                  delay: 1.5, 
                  duration: 0.5,
                  repeat: 2, 
                  repeatType: "reverse" 
                }}
              />

              {/* Pulse Circle around Play Button */}
              <motion.circle
                cx="50"
                cy="50"
                r="12"
                stroke="#0B3954"
                strokeWidth="1"
                fill="none"
                initial={{ scale: 0, opacity: 0 }}
                animate={{ scale: 1.5, opacity: [0, 0.5, 0] }}
                transition={{ delay: 1.8, duration: 1, repeat: Infinity }}
              />
            </svg>
          </motion.div>
        )}

        {stage === 'cc-draw' && (
          <motion.div
            key="cc-stage"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0 }}
          >
            <svg width="400" height="200" viewBox="0 0 200 100">
              <motion.path
                d="M60 30 C 20 30, 20 70, 60 70"
                fill="none" stroke="#0B3954" strokeWidth="8" strokeLinecap="round"
                initial={{ pathLength: 0 }} animate={{ pathLength: 1 }}
                transition={{ duration: 1, ease: "easeInOut" }}
              />
              <motion.path
                d="M140 30 C 100 30, 100 70, 140 70"
                fill="none" stroke="#0B3954" strokeWidth="8" strokeLinecap="round"
                initial={{ pathLength: 0 }} animate={{ pathLength: 1 }}
                transition={{ duration: 1, ease: "easeInOut", delay: 0.2 }}
              />
            </svg>
          </motion.div>
        )}
      </AnimatePresence>

      {/* 2. MAIN CONTENT */}
      {stage === 'main' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 1 }}>

          {/* HEADER - REFINED LOGO SIZE */}
          <header className="fixed top-0 left-0 right-0 h-24 flex items-center justify-between px-10 z-40 bg-white/40 backdrop-blur-2xl border-b border-gray-100">
            <div className="flex items-center"> 
              {/* Using a clean SVG-style text logo for proper sizing and no background */}
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-[#0B3954] rounded-lg flex items-center justify-center">
                   <div className="w-0 h-0 border-t-[6px] border-t-transparent border-l-[10px] border-l-white border-b-[6px] border-b-transparent ml-1"></div>
                </div>
                <span className="text-2xl font-bold tracking-tighter">COURSE<span className="italic font-light">CRAFT</span></span>
              </div>
            </div>

            <div className="flex items-center space-x-10">
              <button className="text-sm font-bold tracking-[0.3em] text-[#0B3954] hover:opacity-50 transition-opacity">LOG IN</button>
              <button className="px-8 py-3 bg-[#0B3954] text-white rounded-full text-xs font-bold tracking-[0.3em] shadow-lg hover:scale-105 active:scale-95 transition-all">
                SIGN UP
              </button>
            </div>
          </header>

          {/* HERO */}
          <section className="h-screen flex flex-col items-center justify-center text-center px-6">
            <motion.div initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.2 }}>
              <h1 className="text-7xl md:text-[11rem] leading-none text-black">
                Welcome to <br />
                <span className="italic font-light text-[#0B3954]">CourseCraft</span>
              </h1>
              <p className="mt-12 text-xl md:text-2xl tracking-[0.6em] uppercase text-gray-300 font-light">
                Skip the scroll. <span className="text-black font-semibold">Learn the goal</span>
              </p>
            </motion.div>
          </section>

          {/* FEATURES - ROTATING BRAND SECTION */}
          <section className="py-40 bg-[#0B3954] text-white overflow-hidden">
            <div className="mb-24 px-16 max-w-7xl mx-auto">
              <h2 className="text-6xl font-serif italic text-white/90">Curated Learning.</h2>
            </div>

            <div className="flex mb-12">
              <motion.div 
                className="flex space-x-10 px-4"
                animate={{ x: [0, -1200] }}
                transition={{ duration: 25, repeat: Infinity, ease: "linear" }}
              >
                {featuresRow1.map((f, i) => (
                  <div key={i} className="min-w-[500px] h-80 p-14 bg-white/5 border border-white/10 rounded-[3.5rem] flex flex-col justify-end group hover:bg-white/10 transition-all cursor-default">
                    <h3 className="text-3xl font-bold mb-4">{f.title}</h3>
